#include <stdio.h>
#include <string.h>

int isVowel(char c) {
    return c=='a' || c=='e' || c=='i' || c=='o' || c=='u';
}

int main() {
    int T; 
    if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int cnt = 0;
        int happy = 0;
        for (int i = 0; S[i]; ++i) {
            if (isVowel(S[i])) {
                cnt++;
                if (cnt > 2) { happy = 1; break; }
            } else {
                cnt = 0;
            }
        }
        if (happy) printf("HAPPY\n");
        else printf("SAD\n");
    }
    return 0;
}

